import React, { useEffect, useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { getMyHistory } from '../services/api';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, PieChart, Pie, Cell, Legend } from 'recharts';
import { Link } from 'react-router-dom';
import './Dashboard.css';

const COLORS = { High: '#ef4444', Moderate: '#f59e0b', Low: '#10b981', Unknown: '#9ca3af' };

export default function Dashboard() {
  const { user } = useAuth();
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    getMyHistory(0, 50)
      .then((r) => setHistory(r.data))
      .catch(() => {})
      .finally(() => setLoading(false));
  }, []);

  // Chart data
  const riskCounts = history.reduce((acc, h) => {
    const r = h.risk_level || 'Unknown';
    acc[r] = (acc[r] || 0) + 1;
    return acc;
  }, {});
  const pieData = Object.entries(riskCounts).map(([name, value]) => ({ name, value }));
  const barData = history.slice(0, 10).map((h) => ({
    name: `${h.drug1} + ${h.drug2}`.substring(0, 20),
    risk: h.confidence_score ? Math.round(h.confidence_score * 100) : 0,
    level: h.risk_level,
  }));

  return (
    <div className="main-content">
      <div className="dashboard fade-up">
        {/* Welcome */}
        <div className="dash-welcome">
          <div>
            <h1 className="section-title">My Dashboard</h1>
            <p className="section-sub">Welcome back, {user?.name} · {user?.role?.replace('_', ' ')}</p>
          </div>
          <Link to="/search" className="btn btn-primary">+ New Search</Link>
        </div>

        {/* Stats */}
        <div className="dash-stats">
          <div className="dash-stat card">
            <span className="dash-stat-val">{history.length}</span>
            <span className="dash-stat-lbl">Total Searches</span>
          </div>
          <div className="dash-stat card">
            <span className="dash-stat-val" style={{ color: '#ef4444' }}>{riskCounts['High'] || 0}</span>
            <span className="dash-stat-lbl">High Risk Found</span>
          </div>
          <div className="dash-stat card">
            <span className="dash-stat-val" style={{ color: '#f59e0b' }}>{riskCounts['Moderate'] || 0}</span>
            <span className="dash-stat-lbl">Moderate Risk</span>
          </div>
          <div className="dash-stat card">
            <span className="dash-stat-val" style={{ color: 'var(--green-600)' }}>{riskCounts['Low'] || 0}</span>
            <span className="dash-stat-lbl">Low / No Risk</span>
          </div>
        </div>

        {history.length > 0 && (
          <div className="dash-charts">
            {/* Pie */}
            <div className="card">
              <h3 className="chart-title">Risk Distribution</h3>
              <ResponsiveContainer width="100%" height={220}>
                <PieChart>
                  <Pie data={pieData} cx="50%" cy="50%" outerRadius={80} dataKey="value" label={({ name, percent }) => `${name} ${(percent * 100).toFixed(0)}%`}>
                    {pieData.map((entry) => (
                      <Cell key={entry.name} fill={COLORS[entry.name] || '#9ca3af'} />
                    ))}
                  </Pie>
                  <Legend />
                </PieChart>
              </ResponsiveContainer>
            </div>

            {/* Bar */}
            <div className="card">
              <h3 className="chart-title">Recent Confidence Scores</h3>
              <ResponsiveContainer width="100%" height={220}>
                <BarChart data={barData} layout="vertical">
                  <XAxis type="number" domain={[0, 100]} unit="%" tick={{ fontSize: 11 }} />
                  <YAxis type="category" dataKey="name" tick={{ fontSize: 10 }} width={130} />
                  <Tooltip formatter={(v) => `${v}%`} />
                  <Bar dataKey="risk" radius={[0, 6, 6, 0]}>
                    {barData.map((entry) => (
                      <Cell key={entry.name} fill={COLORS[entry.level] || '#9ca3af'} />
                    ))}
                  </Bar>
                </BarChart>
              </ResponsiveContainer>
            </div>
          </div>
        )}

        {/* History table */}
        <div className="card">
          <h3 className="chart-title" style={{ marginBottom: 16 }}>Search History</h3>
          {loading ? (
            <div style={{ textAlign: 'center', padding: 32 }}><span className="spinner" /></div>
          ) : history.length === 0 ? (
            <div className="empty-state">
              <p>No searches yet.</p>
              <Link to="/search" className="btn btn-primary btn-sm" style={{ marginTop: 12 }}>Start Searching</Link>
            </div>
          ) : (
            <div className="table-wrap">
              <table>
                <thead>
                  <tr>
                    <th>Drug 1</th><th>Drug 2</th><th>Risk</th>
                    <th>Type</th><th>Confidence</th><th>Date</th>
                  </tr>
                </thead>
                <tbody>
                  {history.map((h) => (
                    <tr key={h.id}>
                      <td style={{ textTransform: 'capitalize' }}>{h.drug1}</td>
                      <td style={{ textTransform: 'capitalize' }}>{h.drug2}</td>
                      <td>
                        <span className={`badge badge-${(h.risk_level || 'unknown').toLowerCase()}`}>
                          {h.risk_level || '—'}
                        </span>
                      </td>
                      <td>{h.interaction_type ? h.interaction_type.replace('_', ' ') : '—'}</td>
                      <td>{h.confidence_score ? `${Math.round(h.confidence_score * 100)}%` : '—'}</td>
                      <td>{h.created_at ? new Date(h.created_at).toLocaleDateString() : '—'}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
